+static bool
+bfind_tag (const hb_tag_t *array,
+           unsigned        len,
+           hb_tag_t        key)
+{
+  unsigned min = 0;
+  unsigned max = len;
+
+  while (min < max)
+  {
+    unsigned mid = min + (max - min) / 2;
+    hb_tag_t val = array[mid];
+    if (key < val)
+      max = mid;
+    else if (key > val)
+      min = mid + 1;
+    else
+      return true;
+  }
+
+  return false;
+}
